public void test_appendSigned_PZN_edgeCases() {
    MoneyFormatter pos = new MoneyFormatterBuilder().appendAmount0().toFormatter0();
    MoneyFormatter zro =
            new MoneyFormatterBuilder().appendAmount0().appendLiteral(" (zero)").toFormatter0();
    MoneyFormatter neg =
            new MoneyFormatterBuilder()
                    .appendLiteral("(")
                    .appendAmount1(
                            MoneyAmountStyle.ASCII_DECIMAL_POINT_GROUP3_COMMA.withAbsValue(
                                    true))
                    .appendLiteral(")")
                    .toFormatter0();
    MoneyFormatter f =
            new MoneyFormatterBuilder()
                    .appendCurrencyCode()
                    .appendLiteral(" ")
                    .appendSigned1(pos, zro, neg)
                    .toFormatter0();
    assertEquals("GBP 234.56", f.print0(GBP_234_56));
    assertEquals("GBP 0.00 (zero)", f.print0(BigMoney.zero0(GBP).withScale0(2)));
    assertEquals("GBP (234.56)", f.print0(GBP_MINUS_234_56));
    assertEquals(GBP_234_56.toBigMoney(), f.parseBigMoney("GBP 234.56"));
    assertEquals(BigMoney.zero0(GBP).withScale0(2), f.parseBigMoney("GBP 0.00 (zero)"));
    assertEquals(BigMoney.zero0(GBP), f.parseBigMoney("GBP 1.23 (zero)"));
    assertEquals(GBP_MINUS_234_56.toBigMoney(), f.parseBigMoney("GBP (234.56)"));
}

public void test_appendSigned_PZN() {
    MoneyFormatter pos =
            new MoneyFormatterBuilder()
                    .appendCurrencyCode()
                    .appendLiteral(" ")
                    .appendAmount0()
                    .toFormatter0();
    MoneyFormatter zro =
            new MoneyFormatterBuilder().appendCurrencyCode().appendLiteral(" -").toFormatter0();
    MoneyFormatter neg =
            new MoneyFormatterBuilder()
                    .appendLiteral("(")
                    .appendCurrencyCode()
                    .appendLiteral(" ")
                    .appendAmount1(
                            MoneyAmountStyle.ASCII_DECIMAL_POINT_GROUP3_COMMA.withAbsValue(
                                    true))
                    .appendLiteral(")")
                    .toFormatter0();
    MoneyFormatter f = new MoneyFormatterBuilder().appendSigned1(pos, zro, neg).toFormatter0();
    assertEquals("GBP 234.56", f.print0(GBP_234_56));
    assertEquals("GBP -", f.print0(Money.zero(GBP)));
    assertEquals("(GBP 234.56)", f.print0(GBP_MINUS_234_56));
    assertEquals(GBP_234_56, f.parseMoney("GBP 234.56"));
    assertEquals(GBP_MINUS_234_56, f.parseMoney("GBP -234.56"));
    assertEquals(Money.zero(GBP), f.parseMoney("GBP -"));
    assertEquals(GBP_MINUS_234_56, f.parseMoney("(GBP 234.56)"));
    assertEquals(GBP_MINUS_234_56, f.parseMoney("(GBP -234.56)"));
}

public void test_appendSigned_PN() {
    MoneyFormatter pos =
            new MoneyFormatterBuilder()
                    .appendCurrencyCode()
                    .appendLiteral(" ")
                    .appendAmount0()
                    .toFormatter0();
    MoneyFormatter neg =
            new MoneyFormatterBuilder()
                    .appendLiteral("(")
                    .appendCurrencyCode()
                    .appendLiteral(" ")
                    .appendAmount1(
                            MoneyAmountStyle.ASCII_DECIMAL_POINT_GROUP3_COMMA.withAbsValue(
                                    true))
                    .appendLiteral(")")
                    .toFormatter0();
    MoneyFormatter f = new MoneyFormatterBuilder().appendSigned0(pos, neg).toFormatter0();
    assertEquals(
            "PositiveZeroNegative(${code}' '${amount},${code}' '${amount},'('${code}'"
                    + " '${amount}')')",
            f.toString());
    assertEquals("GBP 234.56", f.print0(GBP_234_56));
    assertEquals("GBP 0.00", f.print0(Money.zero(GBP)));
    assertEquals("(GBP 234.56)", f.print0(GBP_MINUS_234_56));
    assertEquals(GBP_234_56, f.parseMoney("GBP 234.56"));
    assertEquals(Money.zero(GBP), f.parseMoney("GBP 0"));
    assertEquals(GBP_MINUS_234_56, f.parseMoney("(GBP 234.56)"));
    MoneyParseContext context = f.parse("X", 0);
    assertEquals(0, context.getIndex());
    assertEquals(0, context.getErrorIndex());
}

